function hashFileShort(root, rel) {
  try {
    const abs = path.isAbsolute(rel) ? rel : path.join(root, rel);
    const buf = fs.readFileSync(abs);
    return require('crypto').createHash('sha256').update(buf).digest('hex').slice(0, 12);
  } catch (_) { return ''; }
}

